esqlQuery.esql:
TS metrics-k8sclusterreceiver.otel-*
| STATS restarts = MAX(k8s.container.restarts)
    BY k8s.pod.name, k8s.container.name, k8s.namespace.name
// k8s.container.restarts is a gauge reflecting recent restarts.
// The value resets to 0 when kubelet prunes dead containers,
// so > 0 reliably means "restarting in the recent past".
// Combined with a 15m window and alertDelay of 3, this
// catches sustained crash loops without one-off false positives.
| WHERE restarts > 0
| SORT restarts DESC
| KEEP k8s.namespace.name, k8s.pod.name, k8s.container.name, restarts
| LIMIT 50
